#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char pwd[100];
    int hasUpper = 0, hasLower = 0, hasDigit = 0, hasSpecial = 0;

    printf("Enter password: ");
    fgets(pwd, sizeof(pwd), stdin);
    pwd[strcspn(pwd, "\n")] = '\0';

    int len = strlen(pwd);
    for(int i = 0; i < len; i++) {
        if(isupper(pwd[i])) hasUpper = 1;
        else if(islower(pwd[i])) hasLower = 1;
        else if(isdigit(pwd[i])) hasDigit = 1;
        else hasSpecial = 1;
    }

    int valid = 1;
    if(len < 8) {
        printf("Password too short (minimum 8 characters)\n");
        valid = 0;
    }
    if(!hasUpper) { printf("Missing uppercase letter\n"); valid = 0; }
    if(!hasLower) { printf("Missing lowercase letter\n"); valid = 0; }
    if(!hasDigit) { printf("Missing digit\n"); valid = 0; }
    if(!hasSpecial) { printf("Missing special character\n"); valid = 0; }

    if(valid) printf("Password is valid.\n");
    else printf("Password is invalid.\n");
    return 0;
}
