#include <stdio.h>
#include <limits.h>

int maxDifference(int arr[], int n) {
    if(n < 2) return -1;
    int minSoFar = arr[0];
    int maxDiff = arr[1] - arr[0];

    for(int i = 1; i < n; i++) {
        if(arr[i] - minSoFar > maxDiff)
            maxDiff = arr[i] - minSoFar;
        if(arr[i] < minSoFar)
            minSoFar = arr[i];
    }
    return (maxDiff <= 0) ? -1 : maxDiff;
}

int main() {
    int arr[] = {2, 3, 10, 6, 4, 8, 1};
    int n = sizeof(arr)/sizeof(arr[0]);
    int diff = maxDifference(arr, n);
    printf("Maximum difference: %d\n", diff);
    return 0;
}
```

