#include <stdio.h>
#include <string.h>
#include <stdbool.h>

#define MAX 100

char stack[MAX];
int top = -1;

bool isFull() {
    return top == MAX - 1;
}

bool isEmpty() {
    return top == -1;
}

void push(char ch) {
    if(isFull()) {
        printf("Stack Overflow!\n");
        return;
    }
    stack[++top] = ch;
}

char pop() {
    if(isEmpty()) {
        printf("Stack Underflow!\n");
        return '\0';
    }
    return stack[top--];
}

char peek() {
    if(isEmpty()) return '\0';
    return stack[top];
}

void display() {
    if(isEmpty()) {
        printf("Stack is empty\n");
        return;
    }
    printf("Stack elements: ");
    for(int i = 0; i <= top; i++)
        printf("%c ", stack[i]);
    printf("\n");
}

bool isMatchingPair(char open, char close) {
    return (open == '(' && close == ')') ||
           (open == '{' && close == '}') ||
           (open == '[' && close == ']');
}

bool isBalanced(char *expr) {
    top = -1; // reset stack
    for(int i = 0; expr[i] != '\0'; i++) {
        char ch = expr[i];
        if(ch == '(' || ch == '{' || ch == '[') {
            push(ch);
        } else if(ch == ')' || ch == '}' || ch == ']') {
            if(isEmpty()) return false;
            char topChar = pop();
            if(!isMatchingPair(topChar, ch)) return false;
        }
    }
    return isEmpty();
}

int main() {
    int choice;
    char elem, expr[100];

    do {
        printf("\n===== STACK MENU =====\n");
        printf("1. Push\n");
        printf("2. Pop\n");
        printf("3. Peek\n");
        printf("4. Display\n");
        printf("5. Check Parentheses Balance\n");
        printf("6. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);
        getchar(); // consume newline

        switch(choice) {
            case 1:
                printf("Enter character to push: ");
                scanf("%c", &elem);
                push(elem);
                break;
            case 2:
                elem = pop();
                if(elem != '\0')
                    printf("Popped element: %c\n", elem);
                break;
            case 3:
                elem = peek();
                if(elem != '\0')
                    printf("Top element: %c\n", elem);
                break;
            case 4:
                display();
                break;
            case 5:
                printf("Enter expression (only parentheses): ");
                fgets(expr, sizeof(expr), stdin);
                expr[strcspn(expr, "\n")] = '\0';
                if(isBalanced(expr))
                    printf("Parentheses are BALANCED.\n");
                else
                    printf("Parentheses are NOT BALANCED.\n");
                break;
            case 6:
                printf("Exiting...\n");
                break;
            default:
                printf("Invalid choice!\n");
        }
    } while(choice != 6);

    return 0;
}
```
